def validate_and_deserialize_registration_data(request):
    if not request.is_json:
        return {"error": "Invalid JSON"}, 400

    data = request.get_json()

    if not isinstance(data, dict):
        return {"error": "Invalid JSON structure"}, 400

    required_fields = ['name', 'email', 'password']
    for field in required_fields:
        if field not in data:
            return {"error": f"Missing field: {field}"}, 400
        if not isinstance(data[field], str) or not data[field].strip():
            return {"error": f"Invalid or empty field: {field}"}, 400

    return data, 200

import pytest

def celsius_to_fahrenheit(celsius):
    return celsius * 9/5 + 32

@pytest.mark.parametrize("celsius, expected_fahrenheit", [
    (0, 32),          # Freezing point of water
    (100, 212),       # Boiling point of water
    (37, 98.6),       # Average human body temperature
    (-40, -40),       # Same temperature in both Celsius and Fahrenheit
    (20, 68),         # Room temperature
])
def test_celsius_to_fahrenheit(celsius, expected_fahrenheit):
